import { setup, assign } from 'xstate';

type Ctx = { count: number; min: number; max: number };
type Ev =
  | { type: 'INC' }
  | { type: 'DEC' }
  | { type: 'RESET' };

export const boundedCounter = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
  guards: {
    canInc: ({ context }) => context.count < context.max,
    canDec: ({ context }) => context.count > context.min,
  },
}).createMachine({
  id: 'boundedCounter',
  context: { count: 0, min: 0, max: 100 },
  on: {
    INC: {
      guard: 'canInc',
      actions: assign({ count: ({ context }) => context.count + 1 }),
    },
    DEC: {
      guard: 'canDec',
      actions: assign({ count: ({ context }) => context.count - 1 }),
    },
    RESET: {
      actions: assign({ count: ({ context }) => context.min }),
    },
  },
});
```

