import { setup, assign } from 'xstate';

type Ctx = { window: number[]; size: number };
type Ev =
  | { type: 'HIT' }
  | { type: 'WINDOW_TICK' }
  | { type: 'RESET' };

export const rollingWindow = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
}).createMachine({
  id: 'rollingWindow',
  context: { window: [0, 0, 0, 0, 0], size: 5 },
  on: {
    HIT: {
      actions: assign({
        window: ({ context }) => {
          const next = context.window.slice();
          next[next.length - 1] = next[next.length - 1] + 1;
          return next;
        },
      }),
    },
    WINDOW_TICK: {
      actions: assign({
        window: ({ context }) => [...context.window.slice(1), 0],
      }),
    },
    RESET: {
      actions: assign({
        window: ({ context }) => new Array<number>(context.size).fill(0),
      }),
    },
  },
});
