  types: {
    events: {} as Ev,
  },
}).createMachine({
  id: 'agreeToggle',
  initial: 'unknown',
  states: {
    unknown: {
      on: { AGREE: 'agreed', DECLINE: 'declined' },
    },
    agreed: {
      on: { DECLINE: 'declined', RESET: 'unknown' },
    },
    declined: {
      on: { AGREE: 'agreed', RESET: 'unknown' },
    },
  },
});
