type Ctx = {
  file: File | null;
  url: string | null;
  error: string | null;
};
type Ev =
  | { type: 'SELECT'; file: File }
  | { type: 'UPLOAD' }
  | { type: 'RETRY' };

export const uploadMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
  actors: {
    uploadFile: fromPromise<{ url: string }, { file: File }>(
      async ({ input }) => {
        const body = new FormData();
        body.append('file', input.file);
        const res = await fetch('/upload', { method: 'POST', body });
        if (!res.ok) throw new Error(`upload failed: ${res.status}`);
        return (await res.json()) as { url: string };
      }
    ),
  },
}).createMachine({
  id: 'upload',
  initial: 'idle',
  context: { file: null, url: null, error: null },
  states: {
    idle: {
      on: {
        SELECT: { actions: assign({ file: ({ event }) => event.file }) },
        UPLOAD: { guard: ({ context }) => context.file !== null, target: 'uploading' },
      },
    },
    uploading: {
      invoke: {
        src: 'uploadFile',
        input: ({ context }) => ({ file: context.file as File }),
        onDone: {
          target: 'uploaded',
          actions: assign({ url: ({ event }) => event.output.url }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => (event.error as Error).message,
          }),
        },
      },
    },
    uploaded: {
      type: 'final',
    },
    failed: {
      on: { RETRY: 'uploading' },
    },
  },
});
```

