import { setup, assign, fromPromise } from 'xstate';

type Item = { id: string; name: string };
type Ctx = {
  key: string;
  cache: Record<string, Item>;
  current: Item | null;
  error: string | null;
};
type Ev = { type: 'FETCH'; key: string };

export const cachedFetch = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
  },
  actors: {
    load: fromPromise<Item, { key: string }>(async ({ input }) => {
      const res = await fetch(`/items/${input.key}`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return (await res.json()) as Item;
    }),
  },
  guards: {
    hit: ({ context, event }) =>
      event.type === 'FETCH' && event.key in context.cache,
  },
}).createMachine({
  id: 'cachedFetch',
  initial: 'idle',
  context: { key: '', cache: {}, current: null, error: null },
  states: {
    idle: {
      on: {
        FETCH: [
          {
            guard: 'hit',
            actions: assign({
              current: ({ context, event }) => context.cache[event.key],
              key: ({ event }) => event.key,
            }),
          },
          {
            target: 'loading',
            actions: assign({ key: ({ event }) => event.key }),
          },
        ],
      },
    },
    loading: {
      invoke: {
        src: 'load',
        input: ({ context }) => ({ key: context.key }),
        onDone: {
          target: 'idle',
          actions: assign({
            current: ({ event }) => event.output,
            cache: ({ context, event }) => ({
              ...context.cache,
              [context.key]: event.output,
            }),
          }),
        },
        onError: {
          target: 'idle',
          actions: assign({
            error: ({ event }) => (event.error as Error).message,
          }),
        },
      },
    },
  },
});
